import React, { useEffect, useRef } from 'react';
import { Network } from 'vis-network/standalone/esm/vis-network';
import { useDataProvider } from '../lib/data-provider';
import { CulturalEvent } from '../lib/types';
import { X, Share2 } from 'lucide-react';

interface DNAExplorerProps {
  onClose: () => void;
  rootEventId?: string;
  onSelectNode: (eventId: string) => void;
}

export const CulturalDNAExplorer: React.FC<DNAExplorerProps> = ({ onClose, rootEventId, onSelectNode }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const { events } = useDataProvider();

  useEffect(() => {
    if (!containerRef.current) return;

    // Transform data for Vis.js
    const nodes = events.map(ev => ({
      id: ev.id,
      label: ev.name,
      group: ev.type,
      value: ev.preservation_score, // Size based on preservation
      title: ev.significance, // Tooltip
    }));

    const edges = [];
    events.forEach(ev => {
      ev.dna_relationships.forEach(rel => {
        edges.push({
          from: ev.id,
          to: rel.targetId,
          width: rel.strength * 3,
          color: { opacity: rel.strength },
          dashes: rel.type === 'geographically_linked',
        });
      });
    });

    const data = { nodes, edges };
    const options = {
      nodes: {
        shape: 'dot',
        font: {
          color: '#e2e8f0',
          face: 'Inter',
          size: 14,
        },
        borderWidth: 2,
        color: {
          background: '#1e293b',
          border: '#f59e0b',
          highlight: { background: '#f59e0b', border: '#FFF' },
        },
      },
      edges: {
        color: { color: '#64748b', highlight: '#f59e0b' },
        smooth: { type: 'continuous' },
      },
      physics: {
        stabilization: false,
        barnesHut: {
          gravitationalConstant: -2000,
          springConstant: 0.04,
        },
      },
      interaction: {
        hover: true,
        tooltipDelay: 200,
      },
    };

    const network = new Network(containerRef.current, data, options);

    if (rootEventId) {
      network.selectNodes([rootEventId]);
      network.focus(rootEventId, { scale: 1.2, animation: true });
    }

    network.on('click', (params) => {
      if (params.nodes.length > 0) {
        onSelectNode(params.nodes[0]);
      }
    });

    return () => {
      network.destroy();
    };
  }, [events, rootEventId]);

  return (
    <div className="fixed inset-0 z-[1500] bg-slate-900 flex flex-col">
      <div className="p-6 border-b border-white/5 flex justify-between items-center bg-slate-900/90 backdrop-blur z-10">
        <div>
          <h2 className="text-2xl font-playfair text-white">Cultural DNA Explorer</h2>
          <p className="text-sm text-gray-400">Visualizing structural relationships between traditions</p>
        </div>
        <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors text-white">
          <X size={24} />
        </button>
      </div>

      <div className="flex-1 relative bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-slate-800/50 to-slate-900">
        <div ref={containerRef} className="absolute inset-0" />

        {/* Legend */}
        <div className="absolute bottom-6 left-6 p-4 glass-panel rounded-lg max-w-xs pointer-events-none">
          <h4 className="text-xs uppercase tracking-widest text-gray-500 mb-2">Relationship Types</h4>
          <div className="space-y-2 text-xs text-gray-300">
            <div className="flex items-center gap-2"><span className="w-4 h-0.5 bg-slate-400"></span> Direct Influence</div>
            <div className="flex items-center gap-2"><span className="w-4 h-0.5 border-t border-dashed border-slate-400"></span> Geographic Link</div>
            <div className="flex items-center gap-2"><span className="w-3 h-3 rounded-full border border-amber-500 bg-slate-800"></span> Tradition Node</div>
          </div>
        </div>
      </div>
