// New function for Active Discovery in DNA Explorer
export async function discoverTraditionConnections(topic: string) {
  if (!process.env.API_KEY) {
    throw new Error("API_KEY is missing");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Analyze the cultural tradition or concept: "${topic}".
  1. Identify the core tradition itself (as the root node).
  2. Identify 5-7 related cultural traditions, rituals, or art forms from around the world (focus on structural or thematic similarities).
  3. For each, provide a brief description, a preservation score (0-100 estimate based on global status), and its relationship to "${topic}".

  The relationship type should be one of: 'influenced_by', 'derivative_of', 'shares_root_with', 'geographically_linked'.
  The relationship strength should be between 0.1 (weak) and 1.0 (strong).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            rootNode: {
               type: Type.OBJECT,
               properties: {
                 id: { type: Type.STRING },
                 name: { type: Type.STRING },
                 type: { type: Type.STRING, enum: ['ritual', 'festival', 'artform', 'custom'] },
                 description: { type: Type.STRING },
                 preservation_score: { type: Type.NUMBER },
                 significance: { type: Type.STRING },
               }
            },
            relatedNodes: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  name: { type: Type.STRING },
                  type: { type: Type.STRING, enum: ['ritual', 'festival', 'artform', 'custom'] },
                  description: { type: Type.STRING },
                  preservation_score: { type: Type.NUMBER },
                  significance: { type: Type.STRING },
                  relationshipType: { type: Type.STRING, enum: ['influenced_by', 'derivative_of', 'shares_root_with', 'geographically_linked'] },
                  relationshipStrength: { type: Type.NUMBER },
                }
              }
            }
          }
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Discovery API Error:", error);
    throw error;
  }
}

import React, { useEffect, useRef, useState } from 'react';
import { Network } from 'vis-network/standalone/esm/vis-network';
import { useDataProvider } from '../lib/data-provider';
import { CulturalEvent } from '../lib/types';
import { X, Search, Sparkles, Loader2 } from 'lucide-react';
import { discoverTraditionConnections } from '../services/guru';

interface DNAExplorerProps {
  onClose: () => void;
  rootEventId?: string;
  onSelectNode: (eventId: string) => void;
}

interface GraphNode {
  id: string;
  label: string;
  group: string;
  value: number;
  title: string;
}

interface GraphEdge {
  from: string;
  to: string;
  width: number;
  color: { opacity: number };
  dashes: boolean;
  id?: string;
}

export const CulturalDNAExplorer: React.FC<DNAExplorerProps> = ({ onClose, rootEventId, onSelectNode }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const networkRef = useRef<Network | null>(null);
  const { events } = useDataProvider();

  const [searchQuery, setSearchQuery] = useState('');
  const [isDiscovering, setIsDiscovering] = useState(false);

  // Local state for graph data to allow dynamic updates
  const [graphData, setGraphData] = useState<{nodes: GraphNode[], edges: GraphEdge[]}>({ nodes: [], edges: [] });
  const [initialized, setInitialized] = useState(false);

  // Initialize Data from Provider once
  useEffect(() => {
    if (initialized) return;

    const initialNodes = events.map(ev => ({
      id: ev.id,
      label: ev.name,
      group: ev.type,
      value: ev.preservation_score,
      title: ev.significance,
    }));

    const initialEdges: GraphEdge[] = [];
    events.forEach(ev => {
      ev.dna_relationships.forEach(rel => {
        initialEdges.push({
          from: ev.id,
          to: rel.targetId,
          width: rel.strength * 3,
          color: { opacity: rel.strength },
          dashes: rel.type === 'geographically_linked',
          id: `${ev.id}-${rel.targetId}`
        });
      });
    });

    setGraphData({ nodes: initialNodes, edges: initialEdges });
    setInitialized(true);
  }, [events, initialized]);

  // Initialize/Update Vis Network
  useEffect(() => {
    if (!containerRef.current || !initialized) return;

    if (!networkRef.current) {
      const options = {
        nodes: {
          shape: 'dot',
          font: {
            color: '#e2e8f0',
            face: 'Inter',
            size: 14,
          },
          borderWidth: 2,
          color: {
            background: '#1e293b',
            border: '#f59e0b',
            highlight: { background: '#f59e0b', border: '#FFF' },
          },
        },
        edges: {
          color: { color: '#64748b', highlight: '#f59e0b' },
          smooth: { type: 'continuous' },
        },
        physics: {
          stabilization: false,
          barnesHut: {
            gravitationalConstant: -3000,
            springConstant: 0.04,
            damping: 0.09,
          },
        },
        interaction: {
          hover: true,
          tooltipDelay: 200,
        },
      };

      networkRef.current = new Network(containerRef.current, graphData, options);

      networkRef.current.on('click', (params) => {
        if (params.nodes.length > 0) {
          onSelectNode(params.nodes[0]);
        }
      });

      if (rootEventId) {
        setTimeout(() => {
           networkRef.current?.selectNodes([rootEventId]);
           networkRef.current?.focus(rootEventId, { scale: 1.2, animation: true });
        }, 500);
      }
    } else {
      // Update data without destroying network
      networkRef.current.setData(graphData);
    }
  }, [graphData, initialized, rootEventId, onSelectNode]);

  const handleDiscovery = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;

    setIsDiscovering(true);
    try {
      const result = await discoverTraditionConnections(searchQuery);

      const newNodes: GraphNode[] = [];
      const newEdges: GraphEdge[] = [];
      const existingIds = new Set(graphData.nodes.map(n => n.id));

      // Helper to process node
      const processNode = (nodeData: any) => {
        // Create a unique ID if it doesn't match our 'ev_' convention to avoid collisions
        const id = nodeData.id || `gen_${nodeData.name.toLowerCase().replace(/\s+/g, '_')}`;

        if (!existingIds.has(id)) {
          newNodes.push({
            id: id,
            label: nodeData.name,
            group: nodeData.type,
            value: nodeData.preservation_score || 50,
            title: nodeData.significance || nodeData.description
          });
          existingIds.add(id);
        }
        return id;
      };

      // 1. Process Root
      const rootId = processNode(result.rootNode);

      // 2. Process Related
      result.relatedNodes.forEach((node: any) => {
        const relatedId = processNode(node);

        // Add edge
        const edgeId = `${rootId}-${relatedId}`;
        const reverseEdgeId = `${relatedId}-${rootId}`;

        // Check if edge exists (simple check)
        const edgeExists = graphData.edges.some(e => e.id === edgeId || e.id === reverseEdgeId);

        if (!edgeExists) {
            newEdges.push({
            from: rootId,
            to: relatedId,
            width: (node.relationshipStrength || 0.5) * 3,
            color: { opacity: node.relationshipStrength || 0.5 },
            dashes: node.relationshipType === 'geographically_linked',
            id: edgeId
          });
        }
      });

      // Update State
      setGraphData(prev => ({
        nodes: [...prev.nodes, ...newNodes],
        edges: [...prev.edges, ...newEdges]
      }));

      // Center on new root
      setTimeout(() => {
        networkRef.current?.selectNodes([rootId]);
        networkRef.current?.focus(rootId, { scale: 1.0, animation: true });
      }, 500);

      setSearchQuery('');

    } catch (error) {
      console.error("Failed to discover:", error);
    } finally {
      setIsDiscovering(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[1500] bg-slate-900 flex flex-col">
      {/* Header Bar */}
      <div className="p-4 border-b border-white/5 flex flex-wrap gap-4 justify-between items-center bg-slate-900/90 backdrop-blur z-10">
        <div>
          <h2 className="text-2xl font-playfair text-white flex items-center gap-2">
            Cultural DNA <span className="text-amber-500 text-sm font-sans uppercase tracking-widest border border-amber-500/30 px-2 py-0.5 rounded-full">Explorer</span>
          </h2>
        </div>

        {/* Discovery Search */}
        <div className="flex-1 max-w-md">
            <form onSubmit={handleDiscovery} className="relative group">
              <input 
                type="text" 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Discover new traditions (e.g., 'Kabuki', 'Sufi Whirling')..."
                className="w-full bg-slate-800/50 border border-white/10 rounded-full py-2 pl-10 pr-12 text-sm text-white placeholder-gray-500 focus:outline-none focus:border-amber-500/50 focus:bg-slate-800 transition-all"
                disabled={isDiscovering}
              />
              <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-500 group-focus-within:text-amber-500 transition-colors" size={16} />

              <button 
                type="submit"
                disabled={!searchQuery.trim() || isDiscovering}
                className="absolute right-1 top-1/2 -translate-y-1/2 p-1.5 bg-amber-500/10 hover:bg-amber-500 text-amber-500 hover:text-black rounded-full transition-all disabled:opacity-0"
              >
                {isDiscovering ? <Loader2 size={16} className="animate-spin" /> : <Sparkles size={16} />}
              </button>
            </form>
        </div>

        <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors text-white">
          <X size={24} />
        </button>
      </div>

      {/* Visualization Canvas */}
      <div className="flex-1 relative bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-slate-800/50 to-slate-900">
        <div ref={containerRef} className="absolute inset-0" />

        {/* Loading Overlay */}
        {isDiscovering && (
           <div className="absolute top-4 left-1/2 -translate-x-1/2 bg-slate-900/80 backdrop-blur border border-amber-500/30 px-4 py-2 rounded-full flex items-center gap-3 shadow-xl z-20">
              <Loader2 size={18} className="animate-spin text-amber-500" />
              <span className="text-sm text-amber-100">Consulting cultural archives...</span>
           </div>
        )}

        {/* Legend */}
        <div className="absolute bottom-6 left-6 p-4 glass-panel rounded-lg max-w-xs pointer-events-none">
          <h4 className="text-xs uppercase tracking-widest text-gray-500 mb-2">Relationship Types</h4>
          <div className="space-y-2 text-xs text-gray-300">
            <div className="flex items-center gap-2"><span className="w-4 h-0.5 bg-slate-400"></span> Direct Influence</div>
            <div className="flex items-center gap-2"><span className="w-4 h-0.5 border-t border-dashed border-slate-400"></span> Geographic Link</div>
            <div className="flex items-center gap-2"><span className="w-3 h-3 rounded-full border border-amber-500 bg-slate-800"></span> Tradition Node</div>
          </div>
        </div>
      </div>
    </div>
  );
};

