          </nav>

          {/* 3. Overlays & Modals */}

          {/* Insight Sheet (Only in Map Mode when event selected) */}
          {viewMode === 'PULSE_MAP' && (
            <CulturalInsightSheet 
              event={selectedEvent} 
              allEvents={events}
              onClose={() => setSelectedEvent(null)}
              onNavigateToDNA={(id) => {
                 // Find event by ID needed here, but for now we just switch mode
                 // ideally we pass the ID to DNA explorer state
                 setViewMode('DNA_EXPLORER');
              }} 
            />
          )}

          {/* Full Screen Modes */}
          {viewMode === 'DNA_EXPLORER' && (
            <CulturalDNAExplorer 
              events={events}
              onClose={() => setViewMode('PULSE_MAP')} 
              rootEventId={selectedEvent?.id}
