import { analyzeCulturalSourceMaterial } from '../services/guru';
import { CulturalEvent } from '../lib/types';

interface KnowledgeContributionProps {
  isOpen: boolean;
  onClose: () => void;
  onEventAdded: (event: CulturalEvent) => void;
}

export const KnowledgeContribution: React.FC<KnowledgeContributionProps> = ({ isOpen, onClose, onEventAdded }) => {
  const [activeTab, setActiveTab] = useState<'text' | 'file'>('text');
  const [textInput, setTextInput] = useState('');
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [status, setStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [statusMessage, setStatusMessage] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (file.type === 'application/pdf' || file.type === 'text/plain') {
        setSelectedFile(file);
        setStatus('idle');
      } else {
        setStatus('error');
        setStatusMessage('Only PDF and Text files are supported.');
      }
    }
  };

  const convertFileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const result = reader.result as string;
        // Remove the Data URL prefix (e.g., "data:application/pdf;base64,")
        const base64 = result.split(',')[1];
        resolve(base64);
      };
      reader.onerror = error => reject(error);
    });
  };

  const handleSubmit = async () => {
    if (activeTab === 'text' && !textInput.trim()) return;
    if (activeTab === 'file' && !selectedFile) return;

    setIsAnalyzing(true);
    setStatus('idle');
    setStatusMessage('');

    try {
      let fileData = null;
      let textContent = null;

      if (activeTab === 'file' && selectedFile) {
        const base64 = await convertFileToBase64(selectedFile);
        fileData = { mimeType: selectedFile.type, data: base64 };
      } else {
        textContent = textInput;
      }

      const eventData = await analyzeCulturalSourceMaterial(textContent, fileData);

      // Add generated ID
      const newEvent: CulturalEvent = {
        ...eventData,
        id: `upl_${Date.now()}`,
        related_traditions: [],
        dna_relationships: []
      };

      onEventAdded(newEvent);
      setStatus('success');
      setStatusMessage(`Successfully mapped "${newEvent.name}" to ${newEvent.location.region}.`);

      // Reset form after delay
      setTimeout(() => {
        onClose();
        setStatus('idle');
        setTextInput('');
        setSelectedFile(null);
      }, 2500);

    } catch (error: any) {
      console.error(error);
      setStatus('error');
      setStatusMessage(error.message || "Failed to analyze content. Please try again.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[2200] flex items-center justify-center p-4">
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="absolute inset-0 bg-black/80 backdrop-blur-sm"
          />

          <motion.div
            initial={{ scale: 0.9, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            exit={{ scale: 0.9, opacity: 0 }}
            className="relative w-full max-w-lg glass-panel rounded-2xl overflow-hidden shadow-2xl border border-amber-500/20"
          >
            {/* Header */}
            <div className="p-6 border-b border-white/10 flex justify-between items-center bg-black/40">
              <div>
                <h3 className="text-xl font-playfair text-white flex items-center gap-2">
                  <Upload size={20} className="text-amber-500" />
                  Contribute Knowledge
                </h3>
                <p className="text-xs text-gray-400 mt-1">Upload research or text. AI validates & maps it.</p>
              </div>
              <button onClick={onClose} className="text-gray-500 hover:text-white transition-colors">
                <X size={20} />
              </button>
            </div>

            {/* Tabs */}
            <div className="flex border-b border-white/10">
              <button 
                onClick={() => setActiveTab('text')}
                className={`flex-1 py-3 text-sm font-medium transition-colors ${activeTab === 'text' ? 'bg-amber-500/10 text-amber-500 border-b-2 border-amber-500' : 'text-gray-400 hover:text-gray-200'}`}
              >
                Raw Text
              </button>
              <button 
                onClick={() => setActiveTab('file')}
                className={`flex-1 py-3 text-sm font-medium transition-colors ${activeTab === 'file' ? 'bg-amber-500/10 text-amber-500 border-b-2 border-amber-500' : 'text-gray-400 hover:text-gray-200'}`}
              >
                Upload Document
              </button>
            </div>

            {/* Content */}
            <div className="p-6 bg-[#0f1115]">
              {activeTab === 'text' ? (
                <textarea
                  value={textInput}
                  onChange={(e) => setTextInput(e.target.value)}
                  placeholder="Paste article text, field notes, or descriptions here..."
                  className="w-full h-40 bg-white/5 border border-white/10 rounded-lg p-4 text-sm text-gray-200 focus:outline-none focus:border-amber-500/50 resize-none placeholder-gray-600"
                />
              ) : (
                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className={`
                    w-full h-40 border-2 border-dashed rounded-lg flex flex-col items-center justify-center cursor-pointer transition-all
                    ${selectedFile ? 'border-amber-500/50 bg-amber-500/5' : 'border-white/10 hover:border-white/30 hover:bg-white/5'}
                  `}
                >
                  <input 
                    type="file" 
                    ref={fileInputRef} 
                    onChange={handleFileChange} 
                    accept=".pdf,.txt" 
                    className="hidden" 
                  />
                  {selectedFile ? (
                    <div className="text-center">
                      <FileText size={32} className="mx-auto mb-2 text-amber-500" />
                      <p className="text-sm text-white font-medium">{selectedFile.name}</p>
                      <p className="text-xs text-gray-500 mt-1">{(selectedFile.size / 1024).toFixed(0)} KB</p>
                    </div>
                  ) : (
                    <div className="text-center text-gray-500">
                      <FileType size={32} className="mx-auto mb-2 opacity-50" />
                      <p className="text-sm">Click to upload PDF or TXT</p>
                      <p className="text-xs mt-1 opacity-50">Max 5MB</p>
                    </div>
                  )}
                </div>
              )}

              {/* Status Message */}
              <AnimatePresence>
                {status !== 'idle' && (
                  <motion.div 
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    className={`mt-4 p-3 rounded-lg text-sm flex items-start gap-3 border ${
                      status === 'success' ? 'bg-emerald-900/20 border-emerald-500/30 text-emerald-200' : 'bg-red-900/20 border-red-500/30 text-red-200'
                    }`}
                  >
                    {status === 'success' ? <Check size={16} className="mt-0.5" /> : <AlertCircle size={16} className="mt-0.5" />}
                    <span>{statusMessage}</span>
                  </motion.div>
                )}
              </AnimatePresence>

              {/* Action Button */}
              <button
                onClick={handleSubmit}
                disabled={isAnalyzing || (activeTab === 'text' && !textInput) || (activeTab === 'file' && !selectedFile)}
                className="w-full mt-6 py-3 bg-amber-500 text-black font-semibold rounded-lg hover:bg-amber-400 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2 transition-all shadow-lg shadow-amber-500/20"
              >
                {isAnalyzing ? (
                  <>
                    <Loader2 size={18} className="animate-spin" />
                    Validating & Extracting...
                  </>
                ) : (
                  <>
                    <Sparkles size={18} />
                    Process & Add to Map
                  </>
                )}
              </button>
            </div>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import { Network } from 'vis-network/standalone/esm/vis-network';
import { CulturalEvent } from '../lib/types';
import { X, Search, Sparkles, Loader2, GitBranch } from 'lucide-react';
import { discoverTraditionConnections } from '../services/guru';
import { motion, AnimatePresence } from 'framer-motion';

interface DNAExplorerProps {
  onClose: () => void;
  rootEventId?: string;
  onSelectNode: (eventId: string) => void;
  events: CulturalEvent[];
}

interface GraphNode {
  id: string;
  label: string;
  group: string;
  value: number;
  title: string;
}

interface GraphEdge {
  from: string;
  to: string;
  width: number;
  color: { opacity: number };
  dashes: boolean;
  id?: string;
}

export const CulturalDNAExplorer: React.FC<DNAExplorerProps> = ({ onClose, rootEventId, onSelectNode, events }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const networkRef = useRef<Network | null>(null);

  const [searchQuery, setSearchQuery] = useState('');
  const [isDiscovering, setIsDiscovering] = useState(false);
  const [selectedNodeId, setSelectedNodeId] = useState<string | null>(rootEventId || null);

  // Local state for graph data to allow dynamic updates
  const [graphData, setGraphData] = useState<{nodes: GraphNode[], edges: GraphEdge[]}>({ nodes: [], edges: [] });
  const [initialized, setInitialized] = useState(false);

  // Initialize Data from Props
  useEffect(() => {
    // We only initialize once or when the events array length changes significantly to allow local exploration
    if (initialized && events.length === graphData.nodes.length) return;

    const initialNodes = events.map(ev => ({
      id: ev.id,
      label: ev.name,
      group: ev.type,
      value: ev.preservation_score,
      title: ev.significance,
    }));

    const initialEdges: GraphEdge[] = [];
    events.forEach(ev => {
      ev.dna_relationships.forEach(rel => {
        initialEdges.push({
          from: ev.id,
          to: rel.targetId,
          width: rel.strength * 3,
          color: { opacity: rel.strength },
          dashes: rel.type === 'geographically_linked',
          id: `${ev.id}-${rel.targetId}`
        });
      });
    });

    setGraphData({ nodes: initialNodes, edges: initialEdges });
    setInitialized(true);
  }, [events]);

  // Initialize/Update Vis Network
  useEffect(() => {
    if (!containerRef.current) return;

    if (!networkRef.current) {
      const options = {
        nodes: {
          shape: 'dot',
          font: {
            color: '#e2e8f0',
            face: 'Inter',
            size: 14,
          },
          borderWidth: 2,
          color: {
            background: '#1e293b',
            border: '#f59e0b',
            highlight: { background: '#f59e0b', border: '#FFF' },
          },
        },
        edges: {
          color: { color: '#64748b', highlight: '#f59e0b' },
          smooth: { type: 'continuous' },
        },
        physics: {
          stabilization: false,
          barnesHut: {
            gravitationalConstant: -3000,
            springConstant: 0.04,
            damping: 0.09,
          },
        },
        interaction: {
          hover: true,
          tooltipDelay: 200,
        },
      };

      networkRef.current = new Network(containerRef.current, graphData, options);

      networkRef.current.on('click', (params) => {
        if (params.nodes.length > 0) {
          const nodeId = params.nodes[0];
          setSelectedNodeId(nodeId);
          onSelectNode(nodeId);
        } else {
          setSelectedNodeId(null);
        }
      });

      if (rootEventId) {
        setTimeout(() => {
           networkRef.current?.selectNodes([rootEventId]);
           networkRef.current?.focus(rootEventId, { scale: 1.2, animation: true });
           setSelectedNodeId(rootEventId);
        }, 500);
      }
    } else {
      // Update data without destroying network
      networkRef.current.setData(graphData);
    }
  }, [graphData, rootEventId, onSelectNode]);

  // Helper to normalize IDs to prevent duplicates (e.g., "Theyyam" vs "theyyam")
  const generateStableId = (name: string) => {
    const cleanName = name.toLowerCase().trim().replace(/[^a-z0-9]+/g, '_').replace(/^_+|_+$/g, '');
    return `gen_${cleanName}`;
  };

  const performDiscovery = async (term: string) => {
    setIsDiscovering(true);
    try {
      const result = await discoverTraditionConnections(term);

      // Safety check: ensure result and required fields exist
      if (!result || !result.rootNode) {
          console.error("Invalid discovery response", result);
          return;
      }

      // Clone current state to avoid direct mutation
      const nextNodes = [...graphData.nodes];
      const nextEdges = [...graphData.edges];

      // Create lookup maps for existing data
      const nodeIdMap = new Set(nextNodes.map(n => n.id));
      const nodeLabelMap = new Map(nextNodes.map(n => [n.label.toLowerCase().trim(), n.id]));
      const edgeIdMap = new Set(nextEdges.map(e => e.id));

      // Helper to process and add a node safely
      const getOrAddNode = (nodeData: any) => {
        if (!nodeData || !nodeData.name) return null;

        const normalizedName = nodeData.name.trim();
        const lowerName = normalizedName.toLowerCase();

        // 1. Check if we already have this node by Label (ignoring case)
        if (nodeLabelMap.has(lowerName)) {
            return nodeLabelMap.get(lowerName);
        }

        // 2. Check by ID (if ID provided or generated)
        let id = nodeData.id;
        if (!id || !id.startsWith('gen_')) {
             id = generateStableId(normalizedName);
        }

        // If ID exists (collision), return it
        if (nodeIdMap.has(id)) {
            return id;
        }

        // 3. It is truly new, add it
        const newNode: GraphNode = {
            id: id,
            label: normalizedName,
            group: nodeData.type || 'custom',
            value: nodeData.preservation_score || 50,
            title: nodeData.significance || nodeData.description || 'Discovered via AI'
        };

        nextNodes.push(newNode);
        nodeIdMap.add(id);
        nodeLabelMap.set(lowerName, id);

        return id;
      };

      // 1. Process Root
      const rootId = getOrAddNode(result.rootNode);
      if (!rootId) return;

      // 2. Process Related (with safety check)
      if (result.relatedNodes && Array.isArray(result.relatedNodes)) {
        result.relatedNodes.forEach((node: any) => {
            const relatedId = getOrAddNode(node);

            if (!relatedId || relatedId === rootId) return; // Skip invalid or self-loops

            // Add edge
            // Create a consistent edge ID based on sorted node IDs to prevent A-B and B-A duplicates if directional doesn't matter,
            // or just check both directions if directional matters.
            // Vis.js handles direction, so we typically check specific direction `root -> related`.
            const edgeId = `${rootId}-${relatedId}`;
            const reverseEdgeId = `${relatedId}-${rootId}`;

            // Check if connection already exists in either direction
            if (!edgeIdMap.has(edgeId) && !edgeIdMap.has(reverseEdgeId)) {
                nextEdges.push({
                    from: rootId,
                    to: relatedId,
                    width: (node.relationshipStrength || 0.5) * 3,
                    color: { opacity: node.relationshipStrength || 0.5 },
                    dashes: node.relationshipType === 'geographically_linked',
                    id: edgeId
                });
                edgeIdMap.add(edgeId);
            }
        });
      }

      // Update State
      setGraphData({
        nodes: nextNodes,
        edges: nextEdges
      });

      // Center logic
      setTimeout(() => {
        // If expanding from an existing node, keep focus there but zoom out slightly
        if (selectedNodeId) {
             networkRef.current?.focus(selectedNodeId, { scale: 0.9, animation: true });
        } else {
             networkRef.current?.selectNodes([rootId]);
             networkRef.current?.focus(rootId, { scale: 1.0, animation: true });
        }
      }, 500);

    } catch (error) {
      console.error("Failed to discover:", error);
    } finally {
      setIsDiscovering(false);
    }
  };

  const handleSearchSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;
    await performDiscovery(searchQuery);
    setSearchQuery('');
  };

  const handleExpandSelected = () => {
    if (!selectedNodeId) return;
    const node = graphData.nodes.find(n => n.id === selectedNodeId);
    if (node) {
        performDiscovery(node.label);
    }
  };

  return (
    <div className="fixed inset-0 z-[1500] bg-slate-900 flex flex-col">
      {/* Header Bar */}
      <div className="p-4 border-b border-white/5 flex flex-wrap gap-4 justify-between items-center bg-slate-900/90 backdrop-blur z-10">
        <div className="flex items-center gap-4">
          <h2 className="text-2xl font-playfair text-white flex items-center gap-2">
            Cultural DNA <span className="text-amber-500 text-sm font-sans uppercase tracking-widest border border-amber-500/30 px-2 py-0.5 rounded-full">Explorer</span>
          </h2>

          <AnimatePresence>
            {selectedNodeId && !isDiscovering && (
                <motion.button
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    onClick={handleExpandSelected}
                    className="flex items-center gap-2 px-4 py-1.5 bg-amber-500 text-black text-sm font-medium rounded-full shadow-lg shadow-amber-500/20 hover:bg-amber-400 transition-all"
                >
                    <GitBranch size={16} />
                    <span>Expand Connections</span>
                </motion.button>
            )}
          </AnimatePresence>
        </div>

        {/* Discovery Search */}
        <div className="flex-1 max-w-md flex items-center gap-2">
            <form onSubmit={handleSearchSubmit} className="relative group w-full">
              <input 
                type="text" 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Search new traditions (e.g., 'Kabuki')..."
                className="w-full bg-slate-800/50 border border-white/10 rounded-full py-2 pl-10 pr-12 text-sm text-white placeholder-gray-500 focus:outline-none focus:border-amber-500/50 focus:bg-slate-800 transition-all"
                disabled={isDiscovering}
              />
              <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-500 group-focus-within:text-amber-500 transition-colors" size={16} />

              <button 
                type="submit"
                disabled={!searchQuery.trim() || isDiscovering}
                className="absolute right-1 top-1/2 -translate-y-1/2 p-1.5 bg-amber-500/10 hover:bg-amber-500 text-amber-500 hover:text-black rounded-full transition-all disabled:opacity-0"
              >
                {isDiscovering ? <Loader2 size={16} className="animate-spin" /> : <Sparkles size={16} />}
              </button>
            </form>
        </div>

        <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors text-white">
          <X size={24} />
        </button>
      </div>

      {/* Visualization Canvas */}
      <div className="flex-1 relative bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-slate-800/50 to-slate-900">
        <div ref={containerRef} className="absolute inset-0" />

        {/* Loading Overlay */}
        <AnimatePresence>
            {isDiscovering && (
            <motion.div 
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: 20 }}
                className="absolute top-4 left-1/2 -translate-x-1/2 bg-slate-900/80 backdrop-blur border border-amber-500/30 px-4 py-2 rounded-full flex items-center gap-3 shadow-xl z-20"
            >
                <Loader2 size={18} className="animate-spin text-amber-500" />
                <span className="text-sm text-amber-100">Consulting cultural archives...</span>
            </motion.div>
            )}
        </AnimatePresence>

        {/* Legend */}
        <div className="absolute bottom-6 left-6 p-4 glass-panel rounded-lg max-w-xs pointer-events-none">
          <h4 className="text-xs uppercase tracking-widest text-gray-500 mb-2">Relationship Types</h4>
          <div className="space-y-2 text-xs text-gray-300">
            <div className="flex items-center gap-2"><span className="w-4 h-0.5 bg-slate-400"></span> Direct Influence</div>
            <div className="flex items-center gap-2"><span className="w-4 h-0.5 border-t border-dashed border-slate-400"></span> Geographic Link</div>
            <div className="flex items-center gap-2"><span className="w-3 h-3 rounded-full border border-amber-500 bg-slate-800"></span> Tradition Node</div>
          </div>
        </div>
      </div>
    </div>
  );
};

