                  <span className="text-xs font-semibold uppercase tracking-widest text-amber-500 border border-amber-500/30 px-2 py-0.5 rounded-md bg-amber-500/5">
                    {selectedNode.group}
                  </span>
                  <button 
                    onClick={() => setSelectedNodeId(null)}
                    className="text-gray-400 hover:text-white transition-colors"
                  >
                    <X size={16} />
                  </button>
                </div>
                <h3 className="text-2xl font-playfair text-white leading-tight">{selectedNode.label}</h3>
              </div>

              {/* Panel Content */}
              <div className="flex-1 overflow-y-auto p-5 custom-scrollbar space-y-6">
                {/* Description */}
                <div className="text-sm text-gray-300 leading-relaxed font-light">
